 15	  "We have activated the recovery plan for your delayed order and are coordinating updates through the portal.";
 16	
 17	const COORDINATION_GROUPS = ["Customer Success", "Legal", "Finance", "Support"];
 18	
 19	const DEFAULT_TASK_HORIZON_HOURS = 24;
 20	
 21	export function applyBenchmarkTask(db, now) {
 22	  const request = db.workflow_requests[0];
 23	  const account = db.accounts?.find((item) => item._id === request.accountId) ?? db.accounts?.[0] ?? null;
 24	  const at = now ?? request.generatedAt ?? new Date().toISOString();
 25	  const activities = (db.activities ?? [])
 26	    .filter((item) => item.subjectId === request._id)
 27	    .sort((left, right) => new Date(left.occurredAt) - new Date(right.occurredAt));
 28	  const riskSignals = request.riskSignals.map((signal) => ({
 29	    name: signal.name,
 30	    detail: signal.detail,
 31	    raisedAt: at
 32	  }));
 33	  const activityTimeline = activities.map((activity, index) => ({
 34	    activityId: activity._id,
 35	    summary: activity.summary,
 36	    occurredAt: activity.occurredAt,
 37	    sequence: index + 1,
 38	    customerVisible: false
 39	  }));
 40	  const customerVisibleTimelineEntry = {
 41	    _id: `audit-${request._id}-customer-visible`,
 42	    eventType: "customer-visible-status",
 43	    summary: ESCALATION_STATUS,
 44	    actor: "workflow-engine",
 45	    ownerGroups: [...request.ownerGroups],
 46	    riskSignals: riskSignals.map((signal) => signal.name),
 47	    occurredAt: at,
 48	    customerVisible: true
 49	  };
 50	  const auditTimeline = [...activityTimeline, customerVisibleTimelineEntry];
 51	  const workflowState = {
 52	    _id: `state-${request._id}`,
 53	    requestId: request._id,
 54	    accountId: request.accountId,
 55	    taskId: request.taskId,
 56	    title: request.title,
 57	    status: ESCALATION_STATUS,
 58	    nextStep: request.nextStep,
 59	    recoveryOwner: "Executive Sponsor",
 60	    routing: {
 61	      customerSuccess: "Customer Success",
 62	      legal: "Legal",
 63	      finance: "Finance",
 64	      support: "Support",
 65	      executiveRecoveryOwner: "Executive Sponsor",
 66	      coordinationGroups: [...COORDINATION_GROUPS]
 67	    },
 68	    ownerGroups: [...request.ownerGroups],
 69	    riskSignals,
 70	    context: account
 71	      ? {
 72	          account: {
 73	            accountId: account._id,
 74	            name: account.name,
 75	            tier: account.tier,
 76	            region: account.region
 77	          },
 78	          contract: { ...account.contract },
 79	          support: {
 80	            supportPlan: account.contract?.supportPlan ?? null,
 81	            openCases: account.context?.openCases ?? null,
 82	            contacts: account.contacts.map((contact) => ({
 83	              contactId: contact.contactId,
 84	              role: contact.role,
 85	              email: contact.email
 86	            }))
 87	          },
 88	          invoice: {
 89	            risk: account.context?.invoiceRisk ?? null,
 90	            exposureCents: account.contract?.arrCents ?? null
 91	          },
 92	          usage: {
 93	            healthScore: account.context?.healthScore ?? null,
 94	            usageTrend: account.context?.usageTrend ?? null
 95	          },
 96	          shipment: {
 97	            status: "delayed",
 98	            priority: "high-value",
 99	            orderType: "high-value order"
100	          },
101	          regulatory: {
102	            complianceFlags: [...(account.context?.complianceFlags ?? [])],
103	            legalReview: true
104	          },
105	          audit: {
106	            customerVisible: true,
107	            activityIds: activityTimeline.map((item) => item.activityId),
108	            timeline: auditTimeline
109	          }
110	        }
111	      : null,
112	    auditTimeline,
113	    openedAt: at,
114	    updatedAt: at
115	  };
116	  const ownerTasks = request.ownerGroups.map((ownerGroup, index) => ({
117	    _id: `task-${request._id}-${index + 1}`,
118	    requestId: request._id,
119	    accountId: request.accountId,
120	    ownerGroup,
121	    title: `${ownerGroup} recovery action for ${request.title}`,
122	    status: "open",
123	    dueAt: addHours(at, OWNER_TASK_HORIZON_HOURS[ownerGroup] ?? DEFAULT_TASK_HORIZON_HOURS),
124	    createdAt: at
125	  }));
126	  const customerMessage = {
127	    _id: `message-${request._id}`,
128	    requestId: request._id,
129	    accountId: request.accountId,
130	    channel: "portal",
131	    visibility: "customer",
132	    audience: "customer",
133	    customerSafe: true,
134	    body: request.customerMessage || CUSTOMER_SAFE_MESSAGE,
135	    createdAt: at
136	  };
137	  const auditEvents = [
138	    ...activityTimeline.map((item) => ({
139	      _id: `audit-${item.activityId}`,
140	      requestId: request._id,
141	      accountId: request.accountId,
142	      subjectId: request._id,
143	      type: "account.activity.logged",
144	      summary: item.summary,
145	      occurredAt: item.occurredAt,
146	      customerVisible: false,
147	      sequence: item.sequence
148	    })),
149	    {
150	      _id: `audit-${request._id}-customer-visible`,
151	      requestId: request._id,
152	      accountId: request.accountId,
153	      subjectId: request._id,
154	      type: "escalation.activated",
155	      summary: ESCALATION_STATUS,
156	      actor: "workflow-engine",
157	      ownerGroups: [...request.ownerGroups],
158	      riskSignals: riskSignals.map((signal) => signal.name),
159	      customerVisible: true,
160	      occurredAt: at
161	    }
162	  ];
163	
164	  db.workflow_state = replaceByRequestId(db.workflow_state, request._id, [workflowState]);
165	  db.owner_tasks = replaceByRequestId(db.owner_tasks, request._id, ownerTasks);
166	  db.customer_messages = replaceByRequestId(db.customer_messages, request._id, [customerMessage]);
167	  db.audit_events = replaceByRequestId(db.audit_events, request._id, auditEvents);
168	
169	  return buildPortalView(db);
170	}
171	
172	function replaceByRequestId(collection, requestId, records) {
173	  const existing = collection ?? [];
174	  return existing.filter((item) => item.requestId !== requestId).concat(records);
175	}
176	
177	function addHours(iso, hours) {
178	  const date = new Date(iso);
179	  date.setUTCHours(date.getUTCHours() + hours);
180	  return date.toISOString();
181	}
